#!/bin/bash

cd "$(dirname "$0")/.." || exit

# ---------------------------------------------------------------------------
# Paths
# ---------------------------------------------------------------------------
DATASET_DIR='path to the custom dataset'

# Training: stride-8 overlapping clips (generated by generate_sliding_window_dataset.sh)
TRAIN_CLIPS_DIR="${DATASET_DIR}/videos_train"
LH_TRAIN_ANN="${DATASET_DIR}/train_list_lh.txt"
RH_TRAIN_ANN="${DATASET_DIR}/train_list_rh.txt"

# Validation: non-overlapping stride-16 clips (same as test set)
VAL_CLIPS_DIR="${DATASET_DIR}/videos_val"
LH_VAL_ANN="${DATASET_DIR}/test_list_compositional_lh.txt"
RH_VAL_ANN="${DATASET_DIR}/test_list_compositional_rh.txt"

# Starting checkpoint
CHECKPOINT="${CHECKPOINT:-.path to the checkpoint}"

# Output
OUTPUT_DIR='path to the output directory'

# ---------------------------------------------------------------------------
# Model architecture (must match training)
# ---------------------------------------------------------------------------
LH_NUM_VERBS=5;       LH_NUM_MANIP_OBJS=12;  LH_NUM_TARGET_OBJS=6;  LH_NUM_TOOLS=4
RH_NUM_VERBS=5;       RH_NUM_MANIP_OBJS=12;  RH_NUM_TARGET_OBJS=6;  RH_NUM_TOOLS=4
DECODER_LAYERS=3;     DECODER_HEADS=8;   DECODER_DIM=2048;  DECODER_DROPOUT=0.1
HEAD_DROPOUT=0.1;     ADAPTER_DIM=128

# ---------------------------------------------------------------------------
# Fine-tuning hyper-parameters
# ---------------------------------------------------------------------------
EPOCHS=80
BATCH_SIZE=16
LR=1e-4          # heads / decoder
LR_BACKBONE=1e-5 # shared ViT encoder
TARGET_ACCURACY=0.99   # stop early if val bimanual ≥ 99%

export CUDA_VISIBLE_DEVICES="${CUDA_VISIBLE_DEVICES:-0}"

echo "================================================================"
echo "Case-study fine-tuning  (inference-time preprocessing, no augment)"
echo "================================================================"
echo "Train clips : ${TRAIN_CLIPS_DIR}"
echo "Val clips   : ${VAL_CLIPS_DIR}"
echo "Checkpoint  : ${CHECKPOINT}"
echo "Output      : ${OUTPUT_DIR}"
echo "Epochs      : ${EPOCHS}  |  BS=${BATCH_SIZE}  |  LR_head=${LR}  LR_bb=${LR_BACKBONE}"
echo "================================================================"

python finetune_on_clips.py \
    --clips_dir       "${TRAIN_CLIPS_DIR}" \
    --lh_ann          "${LH_TRAIN_ANN}" \
    --rh_ann          "${RH_TRAIN_ANN}" \
    --val_clips_dir   "${VAL_CLIPS_DIR}" \
    --lh_val_ann      "${LH_VAL_ANN}" \
    --rh_val_ann      "${RH_VAL_ANN}" \
    --checkpoint      "${CHECKPOINT}" \
    --lh_num_verbs       ${LH_NUM_VERBS} \
    --lh_num_manip_objs  ${LH_NUM_MANIP_OBJS} \
    --lh_num_target_objs ${LH_NUM_TARGET_OBJS} \
    --lh_num_tools       ${LH_NUM_TOOLS} \
    --rh_num_verbs       ${RH_NUM_VERBS} \
    --rh_num_manip_objs  ${RH_NUM_MANIP_OBJS} \
    --rh_num_target_objs ${RH_NUM_TARGET_OBJS} \
    --rh_num_tools       ${RH_NUM_TOOLS} \
    --decoder_layers     ${DECODER_LAYERS} \
    --decoder_heads      ${DECODER_HEADS} \
    --decoder_dim        ${DECODER_DIM} \
    --decoder_dropout    ${DECODER_DROPOUT} \
    --head_dropout       ${HEAD_DROPOUT} \
    --adapter_dim        ${ADAPTER_DIM} \
    --use_hand_adapters \
    --epochs         ${EPOCHS} \
    --batch_size     ${BATCH_SIZE} \
    --lr             ${LR} \
    --lr_backbone    ${LR_BACKBONE} \
    --target_accuracy ${TARGET_ACCURACY} \
    --output_dir     "${OUTPUT_DIR}"

echo ""
echo "================================================================"
echo "Fine-tuning complete."
echo "================================================================"
